producers.put_record_boto3:
import boto3, json
kinesis = boto3.client('kinesis', region_name='us-east-1')

# Single record
kinesis.put_record(
    StreamName='order-events',
    Data=json.dumps({'order_id': 123, 'amount': 99.99, 'status': 'placed'}),
    PartitionKey='order-123'  # Same partition key = same shard
)

# Batch records (up to 500 per call, max 5MB)
kinesis.put_records(
    StreamName='order-events',
    Records=[
        {'Data': json.dumps({'order_id': i}), 'PartitionKey': str(i)}
        for i in range(100)
    ]
)

example.state_machine:
{
  "Comment": "Daily ETL Pipeline",
  "StartAt": "ExtractData",
  "States": {
    "ExtractData": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:us-east-1:123:function:Extract",
      "Retry": [{"ErrorEquals": ["States.ALL"], "IntervalSeconds": 5, "MaxAttempts": 3}],
      "Next": "TransformInParallel"
    },
    "TransformInParallel": {
      "Type": "Parallel",
      "Branches": [
        {"StartAt": "TransformOrders", "States": {"TransformOrders": {"Type": "Task", "Resource": "arn:aws:lambda:us-east-1:123:function:TransformOrders", "End": true}}},
        {"StartAt": "TransformProducts", "States": {"TransformProducts": {"Type": "Task", "Resource": "arn:aws:lambda:us-east-1:123:function:TransformProducts", "End": true}}}
      ],
      "Next": "LoadToWarehouse"
    },
    "LoadToWarehouse": {
      "Type": "Task",
      "Resource": "arn:aws:states:::glue:startJobRun.sync",
      "Parameters": {"JobName": "load-to-redshift"},
      "Next": "NotifySuccess"
    },
    "NotifySuccess": {
      "Type": "Task",
      "Resource": "arn:aws:states:::sns:publish",
      "Parameters": {"TopicArn": "arn:aws:sns:us-east-1:123:etl-notifications", "Message": "ETL completed successfully"},
      "End": true
    }
  }
}
